import anthropic
import json
import subprocess
import sys
import tempfile
import os
import base64

client = anthropic.Anthropic()

def build_analysis_agent(csv_path: str):
    """Build a Claude agent that can run Python to analyse a CSV file."""

    tools = [
        {
            "name": "execute_python",
            "description": (
                "Execute Python 3 code to analyse data. "
                "The variable DATA is a pandas DataFrame already loaded from the CSV. "
                "Print results with print(). Save charts with plt.savefig('OUTPUT_DIR/chart.png'). "
                "Timeout is 20 seconds."
            ),
            "input_schema": {
                "type": "object",
                "properties": {
                    "code": {"type": "string", "description": "Python code to run"}
                },
                "required": ["code"]
            }
        }
    ]

    def run_code(code: str) -> dict:
        preamble = (
            "import pandas as pd\nimport numpy as np\n"
            "import matplotlib\nmatplotlib.use('Agg')\n"
            "import matplotlib.pyplot as plt\n"
            "import warnings\nwarnings.filterwarnings('ignore')\n"
            f"import os\nOUTPUT_DIR = {repr(tempfile.mkdtemp())}\n"
            f"DATA = pd.read_csv({repr(csv_path)})\n"
        )
        proc = subprocess.run(
            [sys.executable, "-c", preamble + code],
            capture_output=True, text=True, timeout=25
        )
        output = {"stdout": proc.stdout[:16384], "stderr": proc.stderr[:2048],
                  "error": None if proc.returncode == 0 else proc.stderr[:1024],
                  "figures": {}}
        # Collect any saved figures
        output_dir = preamble.split("OUTPUT_DIR = ")[-1].split("\n")[0].strip("'"")
        if os.path.isdir(output_dir):
            for fname in os.listdir(output_dir):
                with open(os.path.join(output_dir, fname), "rb") as f:
                    output["figures"][fname] = base64.b64encode(f.read()).decode()
        return output

    def analyse(question: str) -> str:
        messages = [{"role": "user", "content": question}]
        while True:
            resp = client.messages.create(
                model="claude-opus-4-8",
                max_tokens=4096,
                tools=tools,
                messages=messages,
            )
            if resp.stop_reason == "end_turn":
                return "\n".join(
                    b.text for b in resp.content if hasattr(b, "text")
                )
            tool_results = []
            for b in resp.content:
                if b.type == "tool_use" and b.name == "execute_python":
                    result = run_code(b.input["code"])
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": b.id,
                        "content": json.dumps(result),
                    })
            messages.append({"role": "assistant", "content": resp.content})
            messages.append({"role": "user", "content": tool_results})

    return analyse

# Usage
analyse = build_analysis_agent("sales_data.csv")
answer = analyse("What are the top 5 products by revenue? Show a bar chart.")
print(answer)

import base64
from pathlib import Path

def render_tool_result(result: dict) -> str:
    """Convert tool result to a string the model can reason about."""
    parts = []
    if result.get("stdout"):
        parts.append(f"Output:\n{result['stdout']}")
    if result.get("error"):
        parts.append(f"Error:\n{result['error']}")
    if result.get("figures"):
        for fname in result["figures"]:
            parts.append(f"Chart saved: {fname} (base64 PNG, {len(result['figures'][fname])} chars)")
    return "\n\n".join(parts) if parts else "(no output)"

# To save a figure for the user
def save_figures(result: dict, output_dir: str):
    Path(output_dir).mkdir(exist_ok=True)
    for fname, b64 in result.get("figures", {}).items():
        out_path = Path(output_dir) / fname
        out_path.write_bytes(base64.b64decode(b64))
        print(f"Saved: {out_path}")

