import duckdb

def make_duckdb_tool(parquet_path: str):
    con = duckdb.connect()

    def execute_python(code: str, timeout: int = 30) -> dict:
        import subprocess, sys
        preamble = (
            "import duckdb, pandas as pd\n"
            f"con = duckdb.connect()\n"
            f"PARQUET_PATH = {repr(parquet_path)}\n"
            # Convenience: con.sql returns a DataFrame
            "sql = lambda q: con.sql(q).df()\n"
        )
        proc = subprocess.run(
            [sys.executable, "-c", preamble + code],
            capture_output=True, text=True, timeout=timeout
        )
        return {"stdout": proc.stdout[:16384],
                "error": None if proc.returncode == 0 else proc.stderr[:2048]}

    return execute_python
